#include "test_last_handle_restore.h"

namespace test_reaction {

LastHandleSnapshot test_last_handle_restore(int initialValue, int updatedValue) {
    // Create a reactive variable
    auto source = reaction::make_source(initialValue);

    // Create a calculation with LastHandle policy
    auto calc = reaction::make_calculation(
        [source_handle = source.get_handle()]() {
            return reaction::resolve(source_handle);
        },
        reaction::HandlePolicy::LastHandle
    );

    // Get the initial result
    int initial_result = reaction::resolve(calc.get_handle());

    // Update the source variable
    reaction::update(source, updatedValue);

    // Get the updated result
    int updated_result = reaction::resolve(calc.get_handle());

    // Close the source node
    reaction::close(source);

    // Get the result after source close
    int after_close_result = reaction::resolve(calc.get_handle());

    // Return last handle snapshot
    return LastHandleSnapshot{
        initial_result,
