inline LogicalExpressionSnapshot test_logical_expression_builders(bool a, bool b, bool c) {
    // 1. Create reactive boolean variables
    reaction::var<bool> var_a = a;
    reaction::var<bool> var_b = b;
    reaction::var<bool> var_c = c;

    // 2. Build logical AND expression
    auto and_expr = reaction::expr([&var_a, &var_b]() {
        return var_a.get() && var_b.get();
    });

    // 3. Build logical OR expression
    auto or_expr = reaction::expr([&var_a, &var_b, &var_c]() {
        return var_a.get() || var_b.get() || var_c.get();
    });

    // 4. Get initial AND and OR results
    bool initial_and_result = and_expr.get();
    bool initial_or_result = or_expr.get();

    // 5. Update variables to trigger recomputation
    var_a = false;
    var_b = false;
    var_c = true;

    // 6. Get updated AND and OR results
    bool updated_and_result = and_expr.get();
    bool updated_or_result = or_expr.get();

    // 7. Return logical expression snapshot
    return LogicalExpressionSnapshot{
        initial_and_result,
        initial_or_result,
        updated_and_result,
        updated_or_result
    };
}

}  // namespace test_reaction
```

This implementation:

1. Creates three reactive boolean variables using `reaction::var<bool>`
2. Builds a logical AND expression that depends on `var_a` and `var_b`
3. Builds a logical OR expression that depends on all three variables
4. Captures the initial results of both expressions
5. Updates all variables to trigger recomputation (setting a and b to false, c to true)
6. Captures the updated results after the changes
7. Returns a snapshot containing both the initial and updated results

The logical expressions are built using `reaction::expr` with lambda functions that capture the reactive variables by reference, ensuring they automatically recompute when any of the dependent variables change.

